// // This module increments a 4-bit counter on each rising edge of the clock when enabled.
module binary_down_counter(
    input wire clk,
    input wire rst_n,
    input wire en,
    output reg [3:0] count
);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        count <= 4'd15;
    else if (en)
        count <= count - 4'd1;
end

endmodule
